    "formState": [
      { "path": "/fridge/input", "type": "string", "owner": "FridgeController.inputText" },
      { "path": "/fridge/ingredients", "type": "Ingredient[]", "owner": "FridgeController.ingredients" },
      { "path": "/filters/mood", "type": "MoodTag|string", "owner": "MoodController/HomeController.selectedMood" },
      { "path": "/filters/time", "type": "MealTime|string", "owner": "MoodController/HomeController.selectedTime" }
    ],
    "computedState": [
      { "path": "/wheel/state", "type": "string", "owner": "HomeController.wheelState", "values": ["idle", "spinning", "settled"] },
      { "path": "/recommendation/current", "type": "Dish|null", "owner": "HomeController.currentDish" },
      { "path": "/fridge/recommendations", "type": "Recommendation[]", "owner": "FridgeController.recommendations" },
      { "path": "/mood/results", "type": "Dish[]", "owner": "MoodController.results" },
      { "path": "/log/todayCount", "type": "number", "owner": "LogController.todayCount" },
      { "path": "/log/entries", "type": "LogEntry[]", "owner": "LogController.entries" },
      { "path": "/share/preview", "type": "ShareCardPreview|null", "owner": "ShareCardController.preview" }
    ]
  },
  "services": [
    {
      "name": "StorageService",
      "responsibility": "Preferences-backed key-value + JSON persistence; initialized with UIAbility context.",
      "api": ["init(context)", "putString(key,val)", "getString(key,def)", "putJson(key,val)", "getJson(key,converter,def)"]
    },
    {
      "name": "LogRepository",
      "responsibility": "CRUD for LogEntry; persists via StorageService; derives todayCount and date filtering.",
      "api": ["getAll()", "addEntry(entry)", "removeEntry(id)", "todayCount()"]
    },
    {
      "name": "RecommendationEngine",
      "responsibility": "Pure logic: spin pick (deterministic post-animation result), ingredient-overlap ranking, mood/time filtering.",
      "api": ["spin(dishes)", "rankByIngredients(dishes,ingredientNames)", "filterByMoodTime(dishes,mood,time)"]
    },
    {
      "name": "ShareCardBuilder",
      "responsibility": "Build a ShareCardPreview from a LogEntry (date/label formatting).",
      "api": ["build(entry)"]
    }
  ],
  "stateMachine": {
    "home": {
      "states": ["idle", "spinning", "settled"],
      "transitions": [
        { "from": "idle|settled", "event": "spin-wheel", "to": "spinning", "then": "settled", "note": "spin result computed on settle" }
      ]
    },
    "share-card": {
      "states": ["closed", "open"],
      "transitions": [
        { "from": "closed", "event": "open-share-card", "to": "open" },
        { "from": "open", "event": "close-share-card", "to": "closed" },
        { "from": "open", "event": "export-share-card", "to": "open", "note": "export side-effect, stays open" }
      ]
    }
  },
  "interactionFlows": [
    {
      "trigger": "home-spin-button / event spin-wheel",
      "inputs": ["wheelSpeed"],
      "steps": [
        "HomeController.wheelState = spinning",
        "RecommendationEngine.spin(dishLibrary) -> Dish",
        "HomeController.currentDish = Dish, wheelState = settled",
        "home-dish-result / home-dish-card reflect currentDish"
      ],
      "sideEffects": [],
      "expectedState": "wheelState=settled, currentDish non-null",
      "errorPath": "If dish library empty -> show fallback text '暂无菜品'"
    },
    {
      "trigger": "home-log-button / event log-current-dish",
      "inputs": ["dishId (currentDish)"],
      "steps": [
        "LogRepository.addEntry(currentDish, inferred mealTime by hour, selectedMood)",
        "LogController refresh; home shows confirmation"
      ],
      "sideEffects": ["persist LogEntry"],
      "expectedState": "todayCount incremented, entry appears in log",
      "errorPath": "If currentDish null -> log button disabled/no-op"
    },
    {
      "trigger": "fridge-add-button / event add-ingredient",
      "inputs": ["ingredientName = fridge-ingredient-input"],
      "steps": [
        "validate non-empty, dedupe by name (case-insensitive)",
        "FridgeController.ingredients.add({id, name})",
        "clear /fridge/input"
      ],
      "expectedState": "fridge-ingredient-list contains new item",
      "errorPath": "Empty/duplicate input -> ignored"
    },
    {
      "trigger": "remove-ingredient",
      "inputs": ["ingredientId"],
      "steps": ["FridgeController.ingredients.remove(id)"],
      "expectedState": "item removed from list"
    },
    {
      "trigger": "fridge-recommend-button / event recommend-by-ingredients",
      "inputs": ["ingredientIds"],
      "steps": [
        "names = ingredients.map(name)",
        "RecommendationEngine.rankByIngredients(dishLibrary, names) -> Recommendation[]",
        "FridgeController.recommendations = result"
      ],
      "expectedState": "fridge-recommendation-list populated or fridge-no-match-state when empty",
      "errorPath": "No ingredients -> empty list + empty-state"
    },
    {
      "trigger": "mood-apply-button / event apply-mood-filters",
      "inputs": ["mood", "time"],
      "steps": [
        "RecommendationEngine.filterByMoodTime(dishLibrary, mood, time) -> Dish[]",
