      const dish = dishes[i];
      let match = 0;
      for (let j = 0; j < normalized.length; j++) {
        if (dish.ingredientNames.indexOf(normalized[j]) >= 0) match++;
      }
      if (match > 0) {
        const total = dish.ingredientNames.length;
        // score = overlap coverage + ingredient efficiency
        const coverage = normalized.length > 0 ? match / normalized.length : 0;
        const efficiency = total > 0 ? match / total : 0;
        const score = coverage * 0.6 + efficiency * 0.4;
        out.push({ dish, matchCount: match, totalIngredients: total, score });
      }
    }
    out.sort((a: Recommendation, b: Recommendation) => {
      if (b.score !== a.score) return b.score - a.score;
      return b.matchCount - a.matchCount;
    });
    return out;
  }

